1	package cli
2	
3	import (
4		"cmp"
5		"context"
6		"encoding/json"
7		"errors"
8		"fmt"
9		"io"
10		"os"
11		"slices"
12		"time"
13	
14		"github.com/agent-sync/agent-sync/internal/coverage"
15		"github.com/agent-sync/agent-sync/internal/engine"
16		"github.com/agent-sync/agent-sync/internal/fsroot"
17		"github.com/agent-sync/agent-sync/internal/harness"
18		"github.com/agent-sync/agent-sync/internal/hierarchy"
19		"github.com/agent-sync/agent-sync/internal/ir"
20		"github.com/agent-sync/agent-sync/internal/manifest"
21		"github.com/agent-sync/agent-sync/internal/report"
22	)
23	
24	// cursorTarget is the adapter name Cursor-rule composition keys on. Kept as a
25	// local literal rather than importing the cursor adapter: composition is a
26	// CLI-orchestration concern and must not couple to adapter internals.
27	const cursorTarget = "cursor"
28	
29	// scopeOutcome is one discovered scope's sync result. Exactly one of Summary
30	// (Err == nil) or Err (a prepare/sync failure for this scope) is meaningful.
31	type scopeOutcome struct {
32		Scope   hierarchy.Scope
33		Summary report.Summary
34		Err     error
35		// Warnings are the coverage gaps for this scope: kinds it emits that the
36		// target tools will not read natively at the scope's level. Empty for
37		// project/user scopes (always native) and for scopes that fail to prepare.
38		Warnings []coverage.Warning
39	}
40	
41	// hierarchySyncOptions carries the per-run knobs the orchestrator applies to
42	// every scope's engine.Request, plus the user-scope toggle.
43	type hierarchySyncOptions struct {
44		IncludeUser bool
45		Frozen      bool
46		PostMerge   bool
47		EngineOpts  engine.Options // mode, adopt, target filter, expect-deletions, logger, now
48	}
49	
50	type preparedLayer struct {
51		Scope        hierarchy.Scope
52		Materialized materialized
53		Manifest     *manifest.Manifest
54	}
55	
56	// runHierarchySync discovers the hierarchy from cwd and runs engine.Sync against
57	// the single selected write scope. A selected scope whose prepare or sync fails
58	// is recorded in its scopeOutcome.Err. Discovery failure aborts the whole run
59	// (the scope set is indeterminate).
60	//
61	// Only emit scopes are synced: the user scope is emitted only when
62	// opts.IncludeUser is set (the --user flag), so a plain repo sync never writes
63	// under the home directory. The orchestration is a CLI-layer loop over the
64	// unmodified engine.Sync; each scope runs against its own fsroot root and so
65	// writes its own staging and ledger.
66	//
67	// The returned notice is advisory. It explains empty runs and reminds callers
68	// when a user scope was discovered but not written.
69	func runHierarchySync(ctx context.Context, rc *runtimeContext, cwd, home string, opts hierarchySyncOptions, now time.Time) ([]scopeOutcome, string, error) {
70		scopes, err := hierarchy.Discover(cwd, hierarchy.Options{Home: home, IncludeUser: opts.IncludeUser})
71		if err != nil {
72			return nil, "", fmt.Errorf("discover hierarchy: %w", err)
73		}
74		scopes = selectWriteScopes(scopes, opts.IncludeUser)
75	
76		preparedLayers := make([]preparedLayer, 0, len(scopes))
77		for _, sc := range scopes {
78			pl, lerr := materializeLayerReadOnly(ctx, rc, sc, now)
79			if lerr != nil {
80				if rc != nil && rc.Logger != nil {
81					rc.Logger.Warn("harness: cannot materialize scope", "path", sc.ManifestPath, "err", lerr)
82				}
83				continue
84			}
85			preparedLayers = append(preparedLayers, pl)
86		}
87	
88		userScope, hasUserScope := hierarchyUserScope(scopes)
89	
90		var outcomes []scopeOutcome
91		for _, sc := range scopes {
92			// Honor cancellation between scopes: a cancelled sync (Ctrl-C, deadline)
93			// must not keep emitting subsequent scopes. engine.Sync also respects ctx,
94			// but this stops the loop before the next scope's prepare/compose work.
95			if err := ctx.Err(); err != nil {
96				return outcomes, "", err
97			}
98			if !sc.Emit {
99				continue // read-only (user) scope shown elsewhere, not emitted
100			}
101			// Run each scope inside a closure so prep.Close runs via defer at the
102			// end of the iteration: the same per-iteration close timing as a manual
103			// Close, but robust against future early returns or a panic in
104			// coverage.Analyze / engine.Sync.
105			out := func() scopeOutcome {
106				out := scopeOutcome{Scope: sc}
107				prep, perr := prepareScopeForSync(ctx, rc, sc.Root, sc.ManifestPath, sc.Level.String(), now, syncPrepareOptions{Frozen: opts.Frozen, PostMerge: opts.PostMerge})
108				if perr != nil {
109					out.Err = perr
110					return out // continue-and-report
111				}
112				defer prep.Close()
113				req := prep.Request
114				req.Options = opts.EngineOpts
115				req.Options.RunLockHeld = prep.RunLockHeld
116				applyResolvedLayers(&req, sc, scopes, preparedLayers)
117				// Fold the user-scope Cursor rule layer into this project scope's node
118				// set (plan U4/D1/D2), via the shared entry point also used by the
119				// single-scope path.
120				applyCursorComposition(ctx, rc, &req, prep.Manifest, req.Scope, userScope, hasUserScope, now)
121				// Coverage warnings are computed from the decoded IR (the distinct
122				// kinds this scope emits), the manifest's targets, and the scope's
123				// level. Computed after a successful prepare (nodes exist);
124				// independent of the sync outcome.
125				out.Warnings = coverage.Analyze(sc.Level, kindsOf(req.Nodes), req.Targets)
126				summary, serr := engine.Sync(ctx, req)
127				if serr != nil {
128					if prep.PinMovedTo != "" {
129						out.Err = pinMovedSyncError(prep.PinMovedTo, serr)
130					} else {
131						out.Err = serr
132					}
133				} else {
134					out.Summary = summary
135					if prep.PinMovedTo != "" && summary.Outcome.ExitCode != 0 {
136						out.Err = pinMovedSyncError(prep.PinMovedTo, fmt.Errorf("sync reported failures: %s", summary.Outcome.Line))
137						out.Summary = report.Summary{}
138					}
139				}
140				return out
141			}()
142			outcomes = append(outcomes, out)
143		}
144	
145		var notice string
146		switch {
147		case len(outcomes) == 0:
148			notice = emptyRunNotice(scopes, cwd)
149		default:
150			// Plan R17: a user manifest that exists but was not synced is worth a
151			// persistent pointer even when project scopes emitted fine — today's
152			// silence is how user-scope config quietly drifts stale.
153			us, ok := skippedUserScope(scopes)
154			if ok {
155				notice = fmt.Sprintf("user-level manifest at %s was not synced; pass --user to include it", us.ManifestPath)
156			}
157		}
158		return outcomes, notice, nil
159	}
160	
161	func selectWriteScopes(scopes []hierarchy.Scope, includeUser bool) []hierarchy.Scope {
162		out := make([]hierarchy.Scope, len(scopes))
163		copy(out, scopes)
164		for i := range out {
165			out[i].Emit = false
166		}
167	
168		if includeUser {
169			for i := range out {
170				if out[i].Level == hierarchy.LevelUser {
171					out[i].Emit = true
172					return out
173				}
174			}
175			return out
176		}
177	
178		for i := len(out) - 1; i >= 0; i-- {
179			if out[i].Level == hierarchy.LevelUser {
180				continue
181			}
182			out[i].Emit = true
183			break
184		}
185	
186		return out
187	}
188	
189	func materializeLayerReadOnly(ctx context.Context, rc *runtimeContext, sc hierarchy.Scope, now time.Time) (preparedLayer, error) {
190		m, err := manifest.LoadFile(sc.ManifestPath, manifest.LoadOptions{NonInteractive: true})
191		if err != nil {
192			return preparedLayer{}, fmt.Errorf("load manifest: %w", err)
193		}
194	
195		root, err := fsroot.OpenWorkspaceRoot(sc.Root)
196		if err != nil {
197			return preparedLayer{}, fmt.Errorf("open scope root: %w", err)
198		}
199		defer func() { _ = root.Close() }()
200	
201		offline := m.Canonical.URL != ""
202		if rc != nil {
203			offline = offline || rc.Flags.Offline
204		}
205		mat, err := materialize(ctx, m, materializeOptions{Offline: offline, Now: now, Root: root})
206		if err != nil {
207			return preparedLayer{}, fmt.Errorf("materialize: %w", err)
208		}
209	
210		return preparedLayer{
211			Scope:        sc,
212			Materialized: mat,
213			Manifest:     m,
214		}, nil
215	}
216	
217	func hierarchyUserScope(scopes []hierarchy.Scope) (hierarchy.Scope, bool) {
218		for _, sc := range scopes {
219			if sc.Level == hierarchy.LevelUser {
220				return sc, true
221			}
222		}
223		return hierarchy.Scope{}, false
224	}
225	
226	func layersForScope(sc hierarchy.Scope, scopes []hierarchy.Scope, preparedLayers []preparedLayer, current harness.Layer) []harness.Layer {
227		preparedByManifest := make(map[string]preparedLayer, len(preparedLayers))
228		for _, pl := range preparedLayers {
229			preparedByManifest[pl.Scope.ManifestPath] = pl
230		}
231		var out []harness.Layer
232		for _, discovered := range scopes {
233			if discovered.ManifestPath == sc.ManifestPath {
234				out = append(out, current)
235				break
236			}
237			if pl, ok := preparedByManifest[discovered.ManifestPath]; ok {
238				out = append(out, layerFromPrepared(pl))
239			}
240		}
241		return out
242	}
243	
244	func layerFromPrepared(pl preparedLayer) harness.Layer {
245		return harness.Layer{
246			Scope:     pl.Scope.Level.String(),
247			Nodes:     pl.Materialized.Nodes,
248			Skills:    pl.Materialized.Skills,
249			Fragments: pl.Materialized.Fragments,
250			SourceURL: pl.Materialized.SourceURL,
251			Commit:    pl.Materialized.Commit,
252		}
253	}
254	
255	func layerFromRequest(req *engine.Request) harness.Layer {
256		return harness.Layer{
257			Scope:     req.Scope,
258			Nodes:     req.Nodes,
259			Skills:    req.Skills,
260			Fragments: req.Fragments,
261			SourceURL: req.SourceURL,
262			Commit:    req.Commit,
263		}
264	}
265	
266	func applyResolvedLayers(req *engine.Request, sc hierarchy.Scope, scopes []hierarchy.Scope, preparedLayers []preparedLayer) {
267		layers := layersForScope(sc, scopes, preparedLayers, layerFromRequest(req))
268		req.Nodes, req.Skills = harness.ResolveNodes(layers, req.Scope)
269		req.Fragments = harness.ResolveFragments(layers, req.Scope)
270	}
271	
272	// skippedUserScope returns the discovered user-level scope that is not being
273	// emitted this run (a plain sync never writes home), when one exists.
274	func skippedUserScope(scopes []hierarchy.Scope) (hierarchy.Scope, bool) {
275		for _, sc := range scopes {
276			if sc.Level == hierarchy.LevelUser && !sc.Emit {
277				return sc, true
278			}
279		}
280		return hierarchy.Scope{}, false
281	}
282	
283	// emptyRunNotice explains a hierarchy sync that discovered zero emit scopes.
284	// Without it the run prints an empty report and exits 0 — indistinguishable
285	// from a successful no-op, which reads as "sync doesn't do anything". Two
286	// cases: discovery found a user-home manifest but it is read-only without
287	// --user (the plain-sync-never-writes-home invariant), or no manifest exists
288	// at all.
289	func emptyRunNotice(scopes []hierarchy.Scope, cwd string) string {
290		for _, sc := range scopes {
291			if sc.Level == hierarchy.LevelUser && !sc.Emit {
292				return fmt.Sprintf("manifest at %s is the user scope and a plain sync never writes to the home directory; run 'agent-sync sync --user' to sync it", sc.ManifestPath)
293			}
294		}
295		return fmt.Sprintf("no .agent-sync.yaml found from %s up to the project root; run 'agent-sync init' to create one", cwd)
296	}
297	
298	// applyCursorComposition folds the user-scope Cursor rule layer into a
299	// project-scope request when the project manifest opts in. It is the single
300	// composition entry point shared by the hierarchy sync loop AND the single-scope
301	// path (validate, watch, sync --workspace), so every command that builds a
302	// project request sees the same composed desired state. Without this, a composed
303	// project would report false `WouldDelete` drift under validate and lose its
304	// composed rules under watch / --workspace sync (the owned-subdir swap wipes
305	// anything not in the freshly-staged set).
306	//
307	// It mutates req in place and returns whether rules were composed. All paths are
308	// gated on m.Compose.CursorRulesFromUser:
309	//   - scope is not project-like: composition is project-only (D1) — warn that
310	//     the opt-in has no effect at this scope, return false. `global` is a
311	//     legacy project-scope alias, so it is project-like for this gate.
312	//   - cursor not a target, or no user manifest at home: silent no-op, false.
313	//   - user source unreadable: defer cursor (drop it from req.Targets) so a
314	//     transient failure can't wipe previously-composed rules; warn; false.
315	//   - rules composed: append to req.Nodes; true.
316	func applyCursorComposition(ctx context.Context, rc *runtimeContext, req *engine.Request, m *manifest.Manifest, scope string, user hierarchy.Scope, hasUser bool, now time.Time) bool {
317		if !m.Compose.CursorRulesFromUser {
318			return false
319		}
320		if !isProjectCompositionScope(scope) {
321			// Directory/user manifest set the opt-in; composition only applies at
322			// project scope. Warn so it isn't a silent no-op.
323			rc.Logger.Warn("compose: cursor-rules-from-user has no effect at this scope; set it on the project manifest", "scope", scope)
324			return false
325		}
326		if !slices.Contains(req.Targets, cursorTarget) {
327			return false
328		}
329		if !hasUser {
330			return false // no user manifest to compose from
331		}
332		composed, failed := composeUserRules(ctx, rc, user, cursorRuleIDsOf(req.Nodes), now)
333		switch {
334		case failed:
335			// The user source could not be read this run (offline URL, malformed user
336			// manifest). Defer the Cursor sync rather than syncing project-only rules:
337			// .cursor/rules/agent-sync/ is an owned subdir replaced by a wholesale
338			// swap, so a project-only sync would wipe the previously-composed rules.
339			// Dropping cursor from this run's targets leaves that subdir untouched; the
340			// next sync that can read the user source re-syncs cursor fully. Project
341			// cursor rule edits wait for that run — the conservative, data-preserving
342			// choice (plan D8, transient-failure guard).
343			req.Targets = withoutTarget(req.Targets, cursorTarget)
344			rc.Logger.Warn("compose: deferring cursor this run — user source unreadable; existing .cursor/rules left intact",
345				"user_manifest", user.ManifestPath)
346			return false
347		case len(composed) > 0:
348			req.Nodes = append(req.Nodes, composed...)
349			return true
350		}
351		return false
352	}
353	
354	func isProjectCompositionScope(scope string) bool {
355		return scope == hierarchy.LevelProject.String() || scope == manifest.ScopeGlobal
356	}
357	
358	// composeUserRules materializes the user-scope manifest read-only and returns
359	// its Cursor `rule` nodes for injection into a project sync (plan D1). The
360	// project root remains the only write target; the user root is opened solely to
361	// read IR.
362	//
363	// It is best-effort (plan D8): any failure — load, open, materialize, offline
364	// or uncached remote source, decode — yields nil plus a warning and never
365	// propagates. A project sync must not fail, block on a trust prompt, or hit the
366	// network because of the user's global manifest. Remote (URL) user sources are
367	// materialized OFFLINE (cache-only) so composition never fetches; a user who
368	// wants a remote source composed pre-populates the cache with `sync --user`.
369	//
370	// projectRuleIDs is the set of `rule` ids already present in the project scope.
371	// A user rule whose id collides is dropped (project wins, matching Cursor's
372	// Team>Project>User precedence) with a per-id warning: the id namespace is flat,
373	// so a coincidental clash must be observable rather than a silent data loss.
374	//
375	// The returned failed flag distinguishes "could not read the user source"
376	// (load/open/materialize error → failed=true) from "read fine, produced zero
377	// composable rules" (failed=false). The caller defers the whole Cursor sync when
378	// failed, so a transient read failure (offline URL, malformed user manifest)
379	// leaves the previously-composed rules in the owned .cursor/rules/ subdir intact
380	// rather than letting the subdir swap wipe them — see the deferral at the call
381	// site (plan D8, transient-failure guard).
382	func composeUserRules(ctx context.Context, rc *runtimeContext, user hierarchy.Scope, projectRuleIDs map[string]struct{}, now time.Time) (nodes []ir.Node, failed bool) {
383		// Deliberately NOT prepareScope: this reads user IR only. prepareScope also
384		// runs DiscoverAdapters (which can launch adapter subprocesses) and builds a
385		// full emit Request — neither is wanted for a read-only compose. Keep the
386		// minimal LoadFile + OpenWorkspaceRoot + materialize path here (D8); do not
387		// "consolidate" it back into prepareScope.
388		log := rc.Logger
389		m, err := manifest.LoadFile(user.ManifestPath, manifest.LoadOptions{NonInteractive: true})
390		if err != nil {
391			log.Warn("compose: cannot read user manifest", "path", user.ManifestPath, "err", err)
392			return nil, true
393		}
394		root, err := fsroot.OpenWorkspaceRoot(user.Root)
395		if err != nil {
396			log.Warn("compose: cannot open user root", "root", user.Root, "err", err)
397			return nil, true
398		}
399		defer func() { _ = root.Close() }()
400	
401		// Never fetch a remote user source during a project sync: force offline for
402		// URL canonicals so an uncached remote soft-no-ops instead of hitting the
403		// network. Local sources are unaffected; an explicit --offline still applies.
404		offline := rc.Flags.Offline || m.Canonical.URL != ""
405		mat, err := materialize(ctx, m, materializeOptions{Offline: offline, Now: now, Root: root})
406		if err != nil {
407			if ctx.Err() != nil {
408				// Cancellation (Ctrl-C, deadline) — not an unreadable user source. The
409				// sync is aborting anyway; don't defer cursor or log a misleading
410				// "source unreadable" warning. Return not-failed so no deferral fires.
411				return nil, false
412			}
413			log.Warn("compose: cannot materialize user IR", "path", user.ManifestPath, "err", err)
414			return nil, true
415		}
416	
417		var out []ir.Node
418		for _, n := range mat.Nodes {
419			if n.Kind != ir.KindRule || !nodeTargetsCursor(n) {
420				continue
421			}
422			if _, clash := projectRuleIDs[n.ID]; clash {
423				log.Warn("compose: user rule shadowed by project rule of the same id", "id", n.ID)
424				continue
425			}
426			// Pin delivery to Cursor only (D1). A user rule with empty frontmatter
427			// targets means "all adapters"; once injected into the project node set it
428			// would otherwise also be written to other rule-supporting targets (e.g.
429			// claude's .claude/rules/). Constrain the injected copy so composition
430			// stays Cursor-only, matching the flag name and docs. n is a range copy;
431			// reassigning its Targets does not mutate the source IR.
432			n.Targets = []string{cursorTarget}
433			// Per-node provenance override (plan U2, resolved Open Question): a
434			// composed node's content comes from the USER scope's source, not the
435			// project's, so its managed header must say so. mat.SourceURL is
436			// already the audit-safe form (canonicalized URL or local path).
437			n.SourceURL = mat.SourceURL
438			n.SourceCommit = mat.Commit
439			out = append(out, n)
440		}
441		// Deterministic injection: sort the composed subset by id and append it after
442		// the project's own nodes (whose order is left untouched). Keeps op/ledger
443		// output and the coverage kind set stable across runs.
444		slices.SortFunc(out, func(a, b ir.Node) int { return cmp.Compare(a.ID, b.ID) })
445		return out, false
446	}
447	
448	// withoutTarget returns a copy of targets with drop removed. Used to defer the
449	// Cursor sync for one run when composition cannot read the user source, so the
450	// owned .cursor/rules/ subdir is not swapped (and previously-composed rules are
451	// not wiped). Returns a fresh slice so the caller's other Request copies keep
452	// the full target list.
453	func withoutTarget(targets []string, drop string) []string {
454		out := make([]string, 0, len(targets))
455		for _, t := range targets {
456			if t != drop {
457				out = append(out, t)
458			}
459		}
460		return out
461	}
462	
463	// nodeTargetsCursor reports whether an IR node is delivered to the Cursor
464	// adapter: an empty Targets list means "all adapters", otherwise it must name
465	// cursor. Mirrors the cursor adapter's own predicate without importing it.
466	func nodeTargetsCursor(n ir.Node) bool {
467		if len(n.Targets) == 0 {
468			return true
469		}
470		return slices.Contains(n.Targets, cursorTarget)
471	}
472	
473	// cursorRuleIDsOf returns the set of ids of the project's `rule` nodes that are
474	// delivered to Cursor, for collision detection against composed user rules.
475	// Restricting to cursor-targeted rules matches the real .cursor/rules namespace:
476	// a project rule targeting only a non-cursor adapter never lands in
477	// .cursor/rules, so it must not shadow (and suppress) a composable user rule.
478	func cursorRuleIDsOf(nodes []ir.Node) map[string]struct{} {
479		ids := make(map[string]struct{})
480		for _, n := range nodes {
481			if n.Kind == ir.KindRule && nodeTargetsCursor(n) {
482				ids[n.ID] = struct{}{}
483			}
484		}
485		return ids
486	}
487	
488	// kindsOf returns the distinct IR kinds present in nodes, preserving
489	// first-seen order. Used to feed coverage.Analyze the scope's emitted kinds.
490	func kindsOf(nodes []ir.Node) []ir.Kind {
491		seen := make(map[ir.Kind]bool, len(nodes))
492		var out []ir.Kind
493		for _, n := range nodes {
494			if seen[n.Kind] {
495				continue
496			}
497			seen[n.Kind] = true
498			out = append(out, n.Kind)
499		}
500		return out
501	}
502	
503	// hierarchyExitCode is non-zero when any scope failed to prepare/sync or any
504	// scope's own summary reported a non-zero exit (continue-and-report: one bad
505	// scope fails the run without blocking the others' emit).
506	//
507	// It preserves the operational/trust exit codes the single-scope path would
508	// surface: a scope error carrying its own ExitCode() (e.g. the trust gate's
509	// exit 3/4/5 from materializeURL) is mapped via MapExit rather than collapsed
510	// to a flat 1. With multiple failing scopes the highest-severity specific code
511	// wins, since codes are assigned in ascending severity (1 generic failure < 2
512	// usage < 3/4/5 trust). An ordinary sync-failure summary (no carried code)
513	// stays at exit 1.
514	func hierarchyExitCode(outcomes []scopeOutcome) int {
515		code := 0
516		for _, o := range outcomes {
517			c := scopeExitCode(o)
518			if c > code {
519				code = c
520			}
521		}
522		return code
523	}
524	
525	// scopeExitCode is the exit code a single scope contributes: 0 when clean, the
526	// scope error's mapped code (MapExit unwraps any exitCoder, e.g. the trust
527	// gate's specific code), or 1 for a summary that reported a non-zero verdict.
528	func scopeExitCode(o scopeOutcome) int {
529		if o.Err != nil {
530			return MapExit(o.Err)
531		}
532		if o.Summary.Outcome.ExitCode != 0 {
533			return o.Summary.Outcome.ExitCode
534		}
535		return 0
536	}
537	
538	// renderHierarchyText writes a per-scope block to w: a header naming the
539	// level and root, then either the scope's report text (success) or its error
540	// line (prepare/sync failure). Mirrors the spacing of renderSummary in
541	// cmd_sync.go (report.RenderText already carries the body's formatting).
542	// A non-empty notice renders as the nothing-to-sync line on a zero-emit run,
543	// or as a trailing note: line after the scope blocks (plan R17).
544	func renderHierarchyText(w io.Writer, outcomes []scopeOutcome, notice string) error {
545		if notice != "" && len(outcomes) == 0 {
546			if _, err := fmt.Fprintf(w, "nothing to sync: %s\n", notice); err != nil {
547				return err
548			}
549		}
550		for i, o := range outcomes {
551			if i > 0 {
552				if _, err := fmt.Fprintln(w); err != nil {
553					return err
554				}
555			}
556			if _, err := fmt.Fprintf(w, "== %s: %s ==\n", o.Scope.Level, o.Scope.Root); err != nil {
557				return err
558			}
559			if o.Err != nil {
560				if _, err := fmt.Fprintf(w, "ERROR: %v\n", o.Err); err != nil {
561					return err
562				}
563			} else if _, err := fmt.Fprint(w, report.RenderText(o.Summary)); err != nil {
564				return err
565			}
566			// Coverage warnings are computed independent of the sync outcome (a
567			// scope can fail to sync after a successful prepare), so render them
568			// even for errored scopes — matching the JSON output, which always
569			// carries coverage_warnings.
570			for _, warn := range o.Warnings {
571				if _, err := fmt.Fprintf(w, "  warning: %s\n", warn.Detail); err != nil {
572					return err
573				}
574			}
575		}
576		if notice != "" && len(outcomes) > 0 {
577			if _, err := fmt.Fprintf(w, "\nnote: %s\n", notice); err != nil {
578				return err
579			}
580		}
581		return nil
582	}
583	
584	// hierarchyScopeJSON is one scope's entry in the aggregate JSON document.
585	// Exactly one of Summary or Error is populated, matching scopeOutcome.
586	type hierarchyScopeJSON struct {
587		Root     string             `json:"root"`
588		Level    string             `json:"level"`
589		Summary  *report.Summary    `json:"summary,omitempty"`
590		Error    string             `json:"error,omitempty"`
591		Warnings []coverage.Warning `json:"coverage_warnings,omitempty"`
592	}
593	
594	// renderHierarchyJSON writes the aggregate machine-readable document: one
595	// entry per emit scope plus the run-wide exit code. The embedded summary uses
596	// the report.Summary JSON tags (the same shape report.MarshalJSON emits).
597	// notice is additive (omitempty) and set only on zero-emit runs, so existing
598	// schema_version 1 consumers are unaffected.
599	func renderHierarchyJSON(w io.Writer, outcomes []scopeOutcome, notice string) error {
600		scopes := make([]hierarchyScopeJSON, 0, len(outcomes))
601		for _, o := range outcomes {
602			entry := hierarchyScopeJSON{
603				Root:     o.Scope.Root,
604				Level:    o.Scope.Level.String(),
605				Warnings: o.Warnings,
606			}
607			if o.Err != nil {
608				entry.Error = o.Err.Error()
609			} else {
610				// Embed the per-scope summary raw: the aggregate is marshaled
611				// below via json.Marshal(doc), which uses report.Summary's struct
612				// tags directly rather than report.MarshalJSON. This is
613				// intentional. The aggregate document carries its own top-level
614				// schema_version, and each embedded summary's JSON matches the
615				// standalone report shape minus that version wrapper (targets is
616				// populated by Summarize, not by the marshaler). Per-scope
617				// summaries deliberately do not repeat schema_version.
618				s := o.Summary
619				entry.Summary = &s
620			}
621			scopes = append(scopes, entry)
622		}
623		doc := struct {
624			SchemaVersion int                  `json:"schema_version"`
625			Scopes        []hierarchyScopeJSON `json:"scopes"`
626			Notice        string               `json:"notice,omitempty"`
627			ExitCode      int                  `json:"exit_code"`
628		}{
629			SchemaVersion: 1,
630			Scopes:        scopes,
631			Notice:        notice,
632			ExitCode:      hierarchyExitCode(outcomes),
633		}
634		data, err := json.Marshal(doc)
635		if err != nil {
636			return fmt.Errorf("cli: marshal hierarchy json: %w", err)
637		}
638		_, err = fmt.Fprintln(w, string(data))
639		return err
640	}
641	
642	// resolveHome resolves the user's home directory for discovery. It is a
643	// package-level var so tests can swap it and keep the suite hermetic (never
644	// touching the real ~); production uses homeDir.
645	var resolveHome = homeDir
646	
647	// homeDir resolves the user's home directory for discovery.
648	func homeDir() (string, error) {
649		h, err := os.UserHomeDir()
650		if err != nil {
651			return "", fmt.Errorf("cli: resolve home: %w", err)
652		}
653		return h, nil
654	}
655	
656	// errUserWithWorkspace is returned when --user is combined with an explicit
657	// --workspace override; the two are mutually exclusive because --workspace
658	// pins a single scope and --user requests the user scope of the hierarchy.
659	var errUserWithWorkspace = errors.New("cli: --user cannot be combined with --workspace (--workspace pins a single scope)")
660

