package sync

import (
	"errors"
	"fmt"
	"io/fs"
	"sort"

	"github.com/agent-sync/agent-sync/internal/fsroot"
	"github.com/agent-sync/agent-sync/internal/ledger"
)

// Orphans returns the paths present in the old ledger but absent from
// the new one — the set to delete on this sync. It is computed from the
// ledger diff ONLY, never from a filesystem scan, so mid-life drift
// (hand-added files) can never induce a phantom orphan deletion.
// Result is sorted for deterministic ordering.
func Orphans(old, next ledger.Ledger) []string {
	keep := make(map[string]bool, len(next.Entries))
	for _, e := range next.Entries {
		keep[e.Path] = true
	}
	var del []string
	for _, e := range old.Entries {
		if !keep[e.Path] {
			del = append(del, e.Path)
		}
	}
	sort.Strings(del)
	return del
}

// DeleteOrphans removes each path through the root. A path already gone
// (out-of-band delete) is a silent no-op — not an error. Must be called
// only AFTER the new ledger is durable, so a crash mid-delete is
// recoverable (the caller owns that ordering). Returns the paths
// actually removed.
func DeleteOrphans(root *fsroot.Root, paths []string) (deleted []string, err error) {
	for _, p := range paths {
		if rerr := root.Inner().Remove(p); rerr != nil {
			if errors.Is(rerr, fs.ErrNotExist) {
				continue
			}
			return deleted, fmt.Errorf("sync: delete orphan %s: %w", p, rerr)
		}
		deleted = append(deleted, p)
	}
	return deleted, nil
}

// CheckExpectedDeletions enforces the --expect-deletions=N safety guard.
// A negative expected means "not specified" and always passes.
func CheckExpectedDeletions(expected, actual int) error {
	if expected >= 0 && expected != actual {
		return fmt.Errorf("%w: expected %d, got %d", ErrDeletionCountMismatch, expected, actual)
	}
	return nil
}

package cli

import "errors"

// Documented process exit codes. Operational failures use exitError
// (from cmd_adapter.go) or these constants; the report verdict carries
// its own 0/1 in report.Outcome.ExitCode.
const (
	exitOK      = 0 // success
	exitFailure = 1 // operation completed but reported failure/drift
	exitUsage   = 2 // usage error, missing required flag, spawn failure
)

// exitCoder is any error that carries its own process exit code (the
// trust package, the adapter exitError, MissingFlagError all implement
// it). MapExit unwraps the chain looking for one.
type exitCoder interface{ ExitCode() int }

// MapExit translates an error returned from command execution into a
// process exit code. nil → 0. An error implementing ExitCode() (anywhere
// in its Unwrap chain) uses that code. Everything else is a generic
// failure (exitUsage), since an unclassified error at the command
// boundary is almost always a usage/operational problem rather than a
// clean "operation reported failure" signal.
func MapExit(err error) int {
	if err == nil {
		return exitOK
	}
	var ec exitCoder
	if errors.As(err, &ec) {
		code := ec.ExitCode()
		// An ExitCode() of 0 on a non-nil error is a contradiction; treat
		// it as a generic failure rather than silently reporting success.
		if code == 0 {
			return exitUsage
		}
		return code
	}
	return exitUsage
}

