	// manifest field, which may embed credentials) or the path string
	// for local_dir / local_path sources. Empty when the caller has no
	// source identity to offer.
	SourceURL string

	Options Options
}

// TargetChange is one target's dry-run result (the Plan path).
type TargetChange struct {
	Target      string
	WouldCreate []string
	WouldUpdate []string
	WouldDelete []string
	Warnings    []string
	Error       string
	OutOfBand   []string // paths whose on-disk hash diverges from the ledger
}

// PlanResult is the result of a dry-run (validate). DriftDetected is true
// when any target has a non-empty change set or out-of-band modification.
type PlanResult struct {
	WorkspacePath string
	Commit        string

	// end of the iteration: the same per-iteration close timing as a manual
	// Close, but robust against future early returns or a panic in
	// coverage.Analyze / engine.Sync.
	out := func() scopeOutcome {
		out := scopeOutcome{Scope: sc}
		prep, perr := prepareScopeForSync(ctx, rc, sc.Root, sc.ManifestPath, sc.Level.String(), now, syncPrepareOptions{Frozen: opts.Frozen, PostMerge: opts.PostMerge})
		if perr != nil {
			out.Err = perr
			return out // continue-and-report
		}
		defer prep.Close()
		req := prep.Request
		req.Options = opts.EngineOpts
		req.Options.RunLockHeld = prep.RunLockHeld
		applyResolvedLayers(&req, sc, scopes, preparedLayers)
		// Data-loss guard (#43 inheritance follow-up): if an ancestor layer
		// this scope inherits from failed to materialize this run, the
		// resolved node set is missing that ancestor's contribution. Rather
		// than let the engine silently delete the previously-inherited paths
		// that dropped out, impose a zero-deletion guard: the sync proceeds
		// only if nothing would be deleted (a fresh scope, or an ancestor
		// that never actually contributed, is unaffected) and otherwise
		// aborts BEFORE any mutation, preserving the inherited content and
		// surfacing a hard error. Skipped when the run already carries an
		// explicit --expect-deletions: an operator who asserted a deletion
		// budget owns that decision and keeps the escape hatch. The ledger
		// records no per-path source, so this cannot distinguish a dropped
		// ancestor's paths from the scope's own removals — it deliberately
		// errs toward refusing.
		failedAncestorPath, failedAncestorErr := firstFailedAncestor(sc, scopes, failedLayers)
		if failedAncestorPath != "" && req.Options.ExpectDeletions == nil {
			zero := 0
			req.Options.ExpectDeletions = &zero
		}
		// Fold the user-scope Cursor rule layer into this project scope's node
		// set (plan U4/D1/D2), via the shared entry point also used by the
		// single-scope path.
		applyCursorComposition(ctx, rc, &req, prep.Manifest, req.Scope, userScope, hasUserScope, now)
		// Coverage warnings are computed from the decoded IR (the distinct
		// kinds this scope emits), the manifest's targets, and the scope's
		// level. Computed after a successful prepare (nodes exist);
		// independent of the sync outcome.
		out.Warnings = coverage.Analyze(sc.Level, kindsOf(req.Nodes), req.Targets)
		summary, serr := engine.Sync(ctx, req)
		if serr != nil {
			// When the zero-deletion guard above tripped, the raw error is a
			// bare "deletion count differs" — opaque to an operator who never
			// set --expect-deletions. Re-frame it around the unreadable
			// inherited layer that is the real cause.
			if failedAncestorPath != "" && errors.Is(serr, syncpkg.ErrDeletionCountMismatch) {
				serr = fmt.Errorf(
					"refusing to sync %s: inherited layer %s could not be materialized this run (%v), "+
						"and proceeding would delete already-inherited content; restore or re-fetch that "+
						"source (e.g. sync its scope online once), then re-run: %w",
					sc.Level, failedAncestorPath, failedAncestorErr, serr)
			}
			if prep.PinMovedTo != "" {
				out.Err = pinMovedSyncError(prep.PinMovedTo, serr)
			} else {
				out.Err = serr
			}
		} else {
			out.Summary = summary
			if prep.PinMovedTo != "" && summary.Outcome.ExitCode != 0 {
				out.Err = pinMovedSyncError(prep.PinMovedTo, fmt.Errorf("sync reported failures: %s", summary.Outcome.Line))
				out.Summary = report.Summary{}
			}
		}
		return out
	}()
	outcomes = append(outcomes, out)
}

